diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..4d4d6178cdbe 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -333,6 +333,18 @@ bool llvm::isKnownNonEqual(const Value *V1, const Value *V2,
                            SimplifyQuery(DL, /*TLI*/ nullptr, DT, AC,
                                          safeCxtI(V2, V1, CxtI), UseInstrInfo));
 }
+static bool isOverflowCheck(const Value *V, const Value *&Add, const Value *&Op0, const Value *&Op1) {
+  ICmpInst::Predicate Pred;
+  if (!match(V, m_ICmp(Pred, m_Value(Add), m_Value(Op0))) || Pred != ICmpInst::ICMP_ULT)
+    return false;
+  Value *A, *B;
+  if (!match(Add, m_Add(m_Value(A), m_Value(B))))
+    return false;
+  if (Op0 != A && Op0 != B)
+    return false;
+  Op1 = (Op0 == A) ? B : A;
+  return true;
+}

 static bool MaskedValueIsZero(const Value *V, const APInt &Mask, unsigned Depth,
                               const SimplifyQuery &Q);
@@ -903,9 +915,20 @@ getKnownBitsFromAndXorOr(const Operator *I, const APInt &DemandedElts,
         KnownOut = KnownRHS.blsi();
     }
     break;
-  case Instruction::Or:
+  case Instruction::Or: {
     KnownOut = KnownLHS | KnownRHS;
+    // Check for overflow checks: (add a, b) < a  OR  (add a, b) < b
+    Value *LHS = I->getOperand(0), *RHS = I->getOperand(1);
+    const Value *Add1, *Add2, *Op0, *Op1, *Op2, *Op3;
+    if (isOverflowCheck(LHS, Add1, Op0, Op1) &&
+        isOverflowCheck(RHS, Add2, Op2, Op3) &&
+        Add1 == Add2 &&
+        ((Op0 == Op2 && Op1 == Op3) || (Op0 == Op3 && Op1 == Op2))) {
+      // The two overflow checks are equivalent.
+      KnownOut = KnownLHS;
+    }
     break;
+  }
   case Instruction::Xor:
     KnownOut = KnownLHS ^ KnownRHS;
     // xor(x, x-1) is common idioms that will clear all but lowest set
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..828aced0691b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3092,6 +3092,41 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return getNewICmpValue(Code, IsSigned, LHS0, LHS1, Builder);
     }
   }
+  // Fold (icmp pred (add A, B), A) | (icmp pred (add A, B), B) -> (icmp pred (add A, B), A)
+  // and similarly for &.
+  // This handles all unsigned predicates (ULT, UGE, UGT, ULE) because they are equivalent.
+  auto getCanonicalAddCheck = [](ICmpInst *Cmp, Value *&Add, Value *&Op,
+                                 ICmpInst::Predicate &CanonicalPred) -> bool {
+    ICmpInst::Predicate Pred = Cmp->getPredicate();
+    Value *LHS = Cmp->getOperand(0), *RHS = Cmp->getOperand(1);
+    // If add is on RHS, swap.
+    if (match(RHS, m_Add(m_Value(), m_Value()))) {
+      std::swap(LHS, RHS);
+      Pred = ICmpInst::getSwappedPredicate(Pred);
+    }
+    if (!match(LHS, m_Add(m_Value(), m_Value())))
+      return false;
+    Value *A, *B;
+    if (!match(LHS, m_Add(m_Value(A), m_Value(B))))
+      return false;
+    if (RHS != A && RHS != B)
+      return false;
+    // After canonicalization, the predicate should be ULT or UGE.
+    if (Pred != ICmpInst::ICMP_ULT && Pred != ICmpInst::ICMP_UGE)
+      return false;
+    Add = LHS;
+    Op = RHS;
+    CanonicalPred = Pred;
+    return true;
+  };
+  Value *AddL, *OpL, *AddR, *OpR;
+  ICmpInst::Predicate CanonicalPredL, CanonicalPredR;
+  if (getCanonicalAddCheck(LHS, AddL, OpL, CanonicalPredL) &&
+      getCanonicalAddCheck(RHS, AddR, OpR, CanonicalPredR) &&
+      AddL == AddR && CanonicalPredL == CanonicalPredR && OpL != OpR) {
+    // The two comparisons are equivalent.
+    return LHS;
+  }

   // handle (roughly):
   // (icmp ne (A & B), C) | (icmp ne (A & D), E)
